    "keywords_raw": ["generalized Heisenberg-type groups", "uniform volume estimates", "Carnot-Carathéodory distances", "Hardy-Littlewood maximal functions", "weak (1,1) estimates", "volume doubling property", "left-invariant Riemannian metrics"],
    "keywords_normalized": ["harmonic analysis", "geometric measure theory", "Lie groups", "maximal functions", "volume doubling"],
    "zh": {
        "tldr": "在广义海森堡型群上，对一大类Carnot-Carathéodory距离定义的球给出了均匀体积估计，并建立了相关中心Hardy-Littlewood极大函数的弱(1,1)估计。",
        "motivation": "扩展文献[BLZ25]的结果，研究广义海森堡型群上的体积估计与极大函数理论。",
        "method": "在群$\mathbb{G}(2n,m,\mathbb{U},\mathbb{W})$上，对一类Carnot-Carathéodory距离分析球的体积增长，并建立极大算子的弱型估计。",
        "result": "获得了均匀体积估计和弱(1,1) $O(C^m n)$-估计，并证明了海森堡群上一类左不变黎曼度量的均匀体积加倍性质。",
        "help_to_user": "提供了广义海森堡型群上体积估计与极大算子理论的统一框架，适用于相关几何分析与偏微分方程研究。",
        "idea_spark": {
            "transferable": "体积估计与极大函数方法可迁移至其他齐性空间或次黎曼流形。",
            "idea": "将经典欧氏空间上的极大算子理论推广到非交换的群结构上。",
            "risk": "广义群结构的复杂性可能增加具体计算的难度。",
            "inspiration": "启发在更一般的Carnot群或分级李群上建立调和分析工具。"
        }
    },
    "en": {
        "tldr": "On generalized Heisenberg-type groups, uniform volume estimates are given for balls defined by a large class of Carnot-Carathéodory distances, and weak (1,1) estimates are established for associated centered Hardy-Littlewood maximal functions.",
        "motivation": "To extend results from [BLZ25] and study volume estimates and maximal function theory on generalized Heisenberg-type groups.",
        "method": "Analyze volume growth of balls defined by Carnot-Carathéodory distances on groups $\mathbb{G}(2n,m,\mathbb{U},\mathbb{W})$, and establish weak-type estimates for maximal operators.",
        "result": "Obtained uniform volume estimates and weak (1,1) $O(C^m n)$-estimates, proving uniform volume doubling property for a class of left-invariant Riemannian metrics on Heisenberg groups.",
        "help_to_user": "Provides a unified framework for volume estimates and maximal operator theory on generalized Heisenberg-type groups, applicable to geometric analysis and PDE studies.",
        "idea_spark": {
            "transferable": "Volume estimation and maximal function methods can be transferred to other homogeneous spaces or sub-Riemannian manifolds.",
            "idea": "Extend classical Euclidean maximal operator theory to non-commutative group structures.",
            "risk": "Complexity of generalized group structures may increase computational difficulty.",
            "inspiration": "Inspires building harmonic analysis tools on more general Carnot groups or graded Lie groups."
        }
    }
}

